      "path": "src/modules/comments/service.js",
      "content": "const { randomUUID } = require('../../lib/id');
const { sendError } = require('../../lib/errors');

const comments = [];

const createComment = async (body) => {
  if (!body.message) {
    throw sendError(400, 'BAD_REQUEST', 'Message is required');
  }
  const comment = { id: randomUUID(), ...body };
  comments.push(comment);
  return comment;
};

const getComments = async (projectId) => {
  return comments.filter(comment => comment.projectId === projectId);
};

module.exports = { createComment, getComments };
